const inp = $input.first().json;
const b = inp.body || inp;

function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

// Normalize incoming form fields
const email = String(b.email || '').trim().toLowerCase();
const name = String(b.name || b.customer_name || '').trim();
const phone = String(b.phone || b.phone_number || '').trim();
const courier = String(b.courier || 'Evri').trim();
const claim_type = String(b.claim_type || 'Lost').trim();
const tracking_number = String(b.tracking_number || '').trim();
const additional_tracking = String(b.additional_tracking || '').trim();
const order_number = String(b.order_number || '').trim();
const delivery_postcode = String(b.delivery_postcode || b.postcode || '').trim();
const parcel_count = Number(b.parcel_count || 1);
const cost_value = Number(b.cost_value || 0); // customer-stated cost of goods
const customer_comment = String(b.customer_comment || b.comment || '').trim();

// Resolve merchant SERVER-SIDE (the customer never selects this).
// Keyed off submission context: a per-merchant token the form embeds (merchant_key)
// or a ?m= query param on the webhook URL.
const merchant_key = String(b.merchant_key || (inp.query && inp.query.m) || 'demo').trim();
const MERCHANTS = {
  'brand-a': { name: 'Brand A Ltd', domain: 'brand-a.example', ceiling: 20 },
  'brand-b': { name: 'Brand B Ltd', domain: 'brand-b.example', ceiling: 25 },
  'demo': { name: 'Demo Merchant', domain: 'demo-merchant.example', ceiling: 20 }
};
const merchant = MERCHANTS[merchant_key] || MERCHANTS['demo'];

// Pricing rule: parcel_value submitted to Evri = merchant ceiling.
// KEEP SEPARATE from cost_value. Client credit = min(cost_value, ceiling).
const parcel_value = merchant.ceiling;

return [{ json: {
  correlation_id: uuidv4(),
  email, name, phone,
  courier, claim_type,
  tracking_number, additional_tracking, order_number,
  delivery_postcode, parcel_count, cost_value, parcel_value,
  customer_comment, merchant
} }];
